// // This module implements a 4-bit up counter that increments on every positive edge of the clock signal, clk. The counter has an active-low synchronous reset signal, reset. When reset is deasserted, the counter should reset to zero.
module down_counter (
	input clk,
	input reset,
	output reg [3:0] count);

always @(posedge clk)
	if (reset)
		count <= 4'b0000;
	else
		count <= count - 1;

endmodule
